import json
import anthropic

# Using tool-call as a structured-output mechanism:
# define a single tool whose input_schema IS the desired response schema.

client = anthropic.Anthropic()

EXTRACTION_TOOL = {
    "name": "record_invoice",
    "description": "Record the extracted invoice data.",
    "input_schema": {
        "type": "object",
        "required": ["vendor", "invoice_number", "total_amount", "currency", "line_items"],
        "properties": {
            "vendor":         {"type": "string"},
            "invoice_number": {"type": "string"},
            "total_amount":   {"type": "number"},
            "currency":       {"type": "string", "enum": ["USD", "EUR", "GBP", "JPY"]},
            "line_items": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["description", "quantity", "unit_price"],
                    "properties": {
                        "description": {"type": "string"},
                        "quantity":    {"type": "integer"},
                        "unit_price":  {"type": "number"},
                    },
                },
            },
        },
    },
}

def extract_invoice(invoice_text: str) -> dict:
    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        tools=[EXTRACTION_TOOL],
        tool_choice={"type": "any"},           # force a tool call
        system=(
            "You are an invoice extraction agent. "
            "Call the record_invoice tool with ALL fields populated from the invoice text. "
            "Do not guess missing fields; use null-equivalent defaults instead."
        ),
        messages=[{"role": "user", "content": f"Extract this invoice:\n\n{invoice_text}"}],
    )
    # Find the tool use block
    for block in message.content:
        if block.type == "tool_use" and block.name == "record_invoice":
            return block.input      # already a validated dict
    raise RuntimeError("Model did not call record_invoice tool")

if __name__ == "__main__":
    sample = """
    Invoice #INV-20240315
    Vendor: Acme Corp
    Items:
      - Widget A   x4   $12.50 each
      - Widget B   x1   $89.00
    Total: USD 139.00
    """
    result = extract_invoice(sample)
    print(json.dumps(result, indent=2))

// Node.js — Anthropic SDK + Zod for schema validation and parse recovery
import Anthropic from "@anthropic-ai/sdk";
import { z } from "zod";

const client = new Anthropic();

// Define expected shape with Zod
const AgentDecisionSchema = z.object({
  action:     z.enum(["search", "answer", "clarify", "escalate"]),
  reasoning:  z.string().min(1),
  query:      z.string().optional(),   // only when action === "search"
  answer:     z.string().optional(),   // only when action === "answer"
});

type AgentDecision = z.infer<typeof AgentDecisionSchema>;

const OUTPUT_INDICATOR = `
Respond with a single JSON object — no prose, no fences:
{
  "action":    "search" | "answer" | "clarify" | "escalate",
  "reasoning": "<one sentence>",
  "query":     "<search query if action is search>",
  "answer":    "<final answer if action is answer>"
}
`;

async function decide(userMessage: string): Promise<AgentDecision> {
  for (let attempt = 0; attempt < 3; attempt++) {
    const response = await client.messages.create({
      model: "claude-opus-4-5",
      max_tokens: 256,
      system: `You are a routing agent.${OUTPUT_INDICATOR}`,
      messages: [{ role: "user", content: userMessage }],
    });

    const raw = response.content
      .filter((b) => b.type === "text")
      .map((b) => b.text)
      .join("");

    try {
      const parsed = JSON.parse(raw.trim());
      return AgentDecisionSchema.parse(parsed);    // throws ZodError if invalid
    } catch (err) {
      console.warn(`Attempt ${attempt + 1} failed:`, (err as Error).message);
    }
  }
  throw new Error("Could not obtain valid decision after 3 attempts");
}

// Usage
const decision = await decide("What is the capital of France?");
console.log(decision);
// { action: "answer", reasoning: "Direct factual question.", answer: "Paris" }
